const fs = require('fs');

const jobId = $('Extract Fields').item.json.job_id;
const channelId = $('Extract Fields').item.json.channel_id;
const userId = $('Extract Fields').item.json.user_id;
const audioFilePath = ($('Extract Fields').item.json.audio_file_path || '').trim();
const audioUrl = ($('Extract Fields').item.json.audio_url || '').trim();

try {
  let audioBytes = null;

  if (audioFilePath && fs.existsSync(audioFilePath)) {
    audioBytes = fs.readFileSync(audioFilePath);
  } else if (audioUrl) {
    const audioResp = await fetch(audioUrl);
    if (!audioResp.ok) {
      throw new Error(`audio fetch failed: ${audioResp.status} ${await audioResp.text()}`);
    }
    audioBytes = Buffer.from(await audioResp.arrayBuffer());
  } else {
    throw new Error('audio_file_path/audio_url 모두 비어 있음');
  }

  const formData = new FormData();
  const audioBlob = new Blob([audioBytes], { type: 'audio/wav' });
  formData.append('file', audioBlob, 'audio.wav');

  const uploadResp = await fetch('https://upload.heygen.com/v1/asset', {
    method: 'POST',
    headers: { 'X-Api-Key': $env.HEYGEN_API_KEY },
    body: formData,
  });

  if (!uploadResp.ok) {
    throw new Error(`HeyGen upload failed: ${uploadResp.status} ${await uploadResp.text()}`);
  }

  const uploadData = await uploadResp.json();
  const assetId = uploadData.data?.id || uploadData.asset_id;
  if (!assetId) {
    throw new Error(`HeyGen upload returned no asset_id: ${JSON.stringify(uploadData)}`);
  }

  const videoBody = {
    video_inputs: [{
      character: {
        type: 'avatar',
        avatar_id: $env.HEYGEN_AVATAR_ID,
        avatar_style: 'normal',
      },
      voice: {
        type: 'audio',
        audio_asset_id: assetId,
      },
    }],
    dimension: { width: 1280, height: 720 },
  };

  const videoResp = await fetch('https://api.heygen.com/v2/video/generate', {
    method: 'POST',
    headers: {
      'X-Api-Key': $env.HEYGEN_API_KEY,
      'Content-Type': 'application/json',
    },
    body: JSON.stringify(videoBody),
  });

  if (!videoResp.ok) {
    throw new Error(`HeyGen create video failed: ${videoResp.status} ${await videoResp.text()}`);
  }

  const videoData = await videoResp.json();
  const videoId = videoData.data?.video_id;
  if (!videoId) {
    throw new Error(`HeyGen create video returned no video_id: ${JSON.stringify(videoData)}`);
  }

  const sleep = (ms) => new Promise((r) => setTimeout(r, ms));
  const maxRetries = 40;
  const intervalMs = 15000;
  let videoUrl = '';
  let status = 'processing';

  for (let i = 0; i < maxRetries; i++) {
    await sleep(intervalMs);
    const pollResp = await fetch(`https://api.heygen.com/v1/video_status.get?video_id=${videoId}`, {
      headers: { 'X-Api-Key': $env.HEYGEN_API_KEY },
    });

    if (!pollResp.ok) {
      status = 'poll_error';
      break;
    }

    const pollData = await pollResp.json();
    status = pollData.data?.status || 'processing';
    if (status === 'completed') {
      videoUrl = pollData.data?.video_url || '';
      break;
    }
    if (status === 'failed') {
      break;
    }
  }

  return {
    json: {
      ok: status === 'completed' && !!videoUrl,
      completed: status === 'completed' && !!videoUrl,
      status,
      video_url: videoUrl,
      video_id: videoId,
      job_id: jobId,
      channel_id: channelId,
      user_id: userId,
    },
  };
} catch (e) {
  const message = e && e.message ? e.message : String(e);
  return {
    json: {
      ok: false,
      completed: false,
      status: 'failed',
      error: message,
      video_url: '',
      job_id: jobId,
      channel_id: channelId,
      user_id: userId,
    },
  };
}
